import React from 'react';
import './App.css';
import { Link, useNavigate } from 'react-router-dom'; 
import {BrowserRouter as Router, Route, Routes} from 'react-router-dom';
import Main_Page from './Main_Page'; // Main_Page м»ҙнҸ¬л„ҢнҠёлҘј мһ„нҸ¬нҠё
import Diarypage from './diarypage';

function App() {
    return (
        <Router>
            <Routes>
                <Route path="/" element={<Main_Page />}/> {/* Main_PageлҘј лЈЁнҠё кІҪлЎңм—җ л ҢлҚ”л§Ғ */}
                <Route path="diarypage" element={<Diarypage />}/> {/* Diarypage кІҪлЎң м„Өм • */}
            </Routes>
        </Router>
    );
}
const Modal = ({ isOpen, onClose }) => { 


    // useNavigateлҠ” м»ҙнҸ¬л„ҢнҠё мғҒлӢЁм—җм„ң нҳём¶ңн•ҙм•ј н•©лӢҲлӢӨ
    const navigate = useNavigate();  // useNavigate нӣ… нҳём¶ң

    // early returnмқҖ useNavigate нӣ… нҳём¶ң мқҙнӣ„м—җ л°°м№ҳн•ҙм•ј н•Ё
    if (!isOpen) return null;  // isOpenмқҙ falseмқј л•Ң лӘЁлӢ¬мқ„ л ҢлҚ”л§Ғн•ҳм§Җ м•ҠмқҢ

    function handleClick() {
        // navigateлЎң нҺҳмқҙм§Җ мқҙлҸҷ
        navigate('/diarypage');
    } 
    return (
        <div className='modal'>
            <ul className='modal_1'>
                <li>
                    {/* нҒҙлҰӯ мӢң navigateлЎң /diarypageлЎң мқҙлҸҷ */}
                    <span onClick={handleClick}>мһҳмһҗмҡ”</span> 
                </li>
                <li>
                    <Link to='/'>м• м№ӯ м„Өм •</Link>
                </li>
                <li>
                    <Link to='/'>Diray List</Link>
                </li>
            </ul>
            <ul className='modal_2'>
                <li></li>
            </ul> 
        </div>
    );
}

export default Modal;
